use rusqlite::Connection;
pub fn ensure_seed(conn: &Connection) { let count: i64 = conn.query_row("SELECT COUNT(*) FROM boards", [], |row| row.get(0)).unwrap_or(0); if count > 0 { return; } conn.execute("INSERT INTO boards (code,name,summary,status,owner) VALUES (?1,?2,?3,?4,?5)", ("NORTH", "North 制作板块", "负责核心创意制作的计划和复盘。", "active", "mara")).ok(); conn.execute("INSERT INTO boards (code,name,summary,status,owner) VALUES (?1,?2,?3,?4,?5)", ("SOUTH", "South 制作板块", "处理延期和跨团队交接。", "review", "riley")).ok(); conn.execute("INSERT INTO work_items (board_code,title,stage,priority,due_date,details) VALUES ('NORTH','Refresh weekly pack','draft','high','2026-06-06','整理每周同步包。')", []).ok(); conn.execute("INSERT INTO work_items (board_code,title,stage,priority,due_date,details) VALUES ('NORTH','Audit overdue backlog','active','medium','2026-06-08','盘点超期事项。')", []).ok(); conn.execute("INSERT INTO work_items (board_code,title,stage,priority,due_date,details) VALUES ('SOUTH','Align handoff notes','review','high','2026-06-04','补齐 handoff note。')", []).ok(); }
